var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>선두 차량이 강경파 반군들의 활동권에 진입했다.</color>","JPN":"<color=#ffd34c>先頭車両が強硬派反乱軍の活動圏内に入った。</color>","ENG":"<color=#ffd34c>The vehicle in the lead entered the hardliner rebels' active area.</color>","TWN":"<color=#ffd34c>報告，前導車已進入強硬派叛軍的活動範圍內。</color>"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"다들 정신 바짝 차려. 침식체만큼 위험하고 정신 나간 놈들이야.","JPN":"みんな、気を抜くな。侵食体と同じぐらい危険で、イカれた連中だ。","ENG":"Stay alert. They're as dangerous and insane as C.O.s.","TWN":"大家要繃緊神經，他們的危險和瘋狂程度絲毫不亞於侵蝕體。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"경계 철저히 하고. 수상한 게 있으면 절대 놓치지 마.","JPN":"徹底して警戒し、怪しい動きは絶対に見逃すな。","ENG":"Be vigilant. Don't let anything suspicious leave your sight.","TWN":"提高警覺，一旦發現可疑人士就絕對不能放過。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"안심하세요, 부인. 이 도로를 쭉 따라가면 곧 타나베린에 닿을 겁니다.","JPN":"安心してください、夫人。この道路に沿って行けば、すぐタナベリンに着きます。","ENG":"Don't worry, Mrs. Schneider. If we stay on this road, we'll soon reach Tanaberin.","TWN":"請放心，夫人，沿著這條路一直走就會到達那貝林。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"고마워요. 젊은 사람들이 늙은이 한 명 때문에 이렇게까지 애써 주고.","JPN":"本当に感謝します。若い皆さんが私のような年寄りのためにこんなに頑張ってくださって。","ENG":"Thank you. I appreciate all you young men looking out for one old lady.","TWN":"謝謝，因為我一個老太，害你們這麼大費周章。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그런 말씀 마십시오. 이게 저희 일이니까요.","JPN":"そんなことをおっしゃらないでください。これが私たちの仕事ですから。","ENG":"Don’t say that. This is part of our job.","TWN":"別這麼說，這是我們應該做的。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하지만…. 사람들이 많이 죽었잖아요?","JPN":"でも……大勢の方々がお亡くなりになったでしょう？","ENG":"But... a lot of people died, haven't they?","TWN":"但是……不是很多人因此犧牲嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"부인, 그건……","JPN":"夫人、それは……","ENG":"Mrs. Schneider, that's...","TWN":"夫人，這……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"이상하죠. 안젤라가 보살펴 줄 때는 머릿속이 자주 뿌옇게 물들었어요.","JPN":"変ですよね。アンジェラに世話をしてもらっていた頃は頭の中に霧がかかっているようでした。","ENG":"Strange. My head used to blur quite often when Angela took care of me.","TWN":"很奇怪。安潔拉照顧我的時候，總覺得腦袋迷迷糊糊的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그런데 지금은…. 혼자라 적적하지만 머릿속이 점점 맑아지는 기분이에요.","JPN":"でも今は……一人で寂しくはありますが、頭の中がだんだん鮮明になってきている感じがします。","ENG":"But now... I'm lonely, but I feel like I have more clarity.","TWN":"現在只剩我自己一個……感覺有點孤單，但頭腦卻清醒許多。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"나이가 들면서 주변 사람들을 참 많이도 고생시키는 것 같아요.","JPN":"歳を取ると、周りに迷惑ばかりかけてしまいますね。","ENG":"It seems like I've been aging and only causing trouble for those around me.","TWN":"上了年紀後，好像給周圍的人造成很多麻煩。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아…. 우리 딸도….","JPN":"レア……私の娘にも……","ENG":"And my daughter... Leah...","TWN":"蕾亞……我的女兒也……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"너무 자책하지 마세요, 부인.","JPN":"あまり自分を責めないでください、夫人。","ENG":"Don't blame yourself, Mrs. Schneider.","TWN":"請不要自責，夫人。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"병원에서 정신 질환도 침식 증후군 때문이라고 했다면서요.","JPN":"病院では精神疾患も侵食症候群によるものと診断されたそうではないですか。","ENG":"Didn't the doctor say that your mental illness was caused by Corruption Syndrome?","TWN":"醫生也說過你的精神疾病是侵蝕症候群所引起的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"나쁜 건 병이지 부인이 아니에요. 따님도─","JPN":"悪いのは病気であって、夫人ではありませんよ。娘さんも──","ENG":"The illness is to blame, not you. I'm sure your daughter–","TWN":"是生病的關係，不是你的問題。你女兒也……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};